export * from './input-otp-group.component';
export * from './input-otp-separator.component';
export * from './input-otp-slot.component';
export * from './input-otp.component';
export * from './input-otp.variants';
export * from './input-otp.imports';

import { ChangeDetectionStrategy, Component, ViewEncapsulation } from '@angular/core';

@Component({
  selector: 'hb-input-otp-group',
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: { class: 'flex items-center', '[attr.data-slot]': "'input-otp-group'" },
  exportAs: 'hbInputOtpGroup',
})
export class HbInputOtpGroupComponent {}

import { ChangeDetectionStrategy, Component, ViewEncapsulation } from '@angular/core';
import { NgIcon, provideIcons } from '@ng-icons/core';
import { phosphorMinus } from '@ng-icons/phosphor-icons/regular';

@Component({
  selector: 'hb-input-otp-separator',
  imports: [NgIcon],
  viewProviders: [provideIcons({ phosphorMinus })],
  template: `<ng-content><ng-icon name="phosphorMinus" /></ng-content>`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    role: 'separator',
    class: 'inline-flex items-center text-muted-foreground',
    '[attr.data-slot]': "'input-otp-separator'",
  },
  exportAs: 'hbInputOtpSeparator',
})
export class HbInputOtpSeparatorComponent {}

import {
  ChangeDetectionStrategy,
  Component,
  computed,
  inject,
  input,
  numberAttribute,
  ViewEncapsulation,
} from '@angular/core';

import { cn, type ClassValue } from '{{alias}}/utils';
import { HbInputOtpComponent } from './input-otp.component';
import { inputOtpSlotVariants } from './input-otp.variants';

@Component({
  selector: 'hb-input-otp-slot',
  template: `
    @if (char()) {
      <span>{{ char() }}</span>
    } @else if (caret()) {
      <span class="hb-input-otp-caret" aria-hidden="true"></span>
    }
  `,
  styles: `
    .hb-input-otp-caret {
      display: block;
      width: 1px;
      height: 1rem;
      background: var(--foreground);
      animation: hb-input-otp-caret-blink 1s steps(1) infinite;
    }
    @keyframes hb-input-otp-caret-blink {
      0%,
      50% {
        opacity: 1;
      }
      50.01%,
      100% {
        opacity: 0;
      }
    }
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  host: {
    '[class]': 'classes()',
    'aria-hidden': 'true',
    '[attr.data-slot]': "'input-otp-slot'",
    '[attr.data-active]': 'active() || null',
    '[attr.data-status]': 'otp.status()',
    '[attr.data-disabled]': 'otp.isDisabled() || null',
  },
  exportAs: 'hbInputOtpSlot',
})
export class HbInputOtpSlotComponent {
  protected readonly otp = inject(HbInputOtpComponent);

  readonly hbIndex = input.required<number, unknown>({ transform: numberAttribute });
  readonly class = input<ClassValue>('');

  protected readonly char = computed(() => this.otp.charAt(this.hbIndex()));
  protected readonly active = computed(() => this.otp.isActive(this.hbIndex()));
  protected readonly caret = computed(() => this.otp.showCaret(this.hbIndex()));
  protected readonly classes = computed(() =>
    cn(
      inputOtpSlotVariants({
        size: this.otp.size(),
        status: this.otp.status(),
        ring: this.otp.ring(),
      }),
      this.class(),
    ),
  );
}

import {
  afterNextRender,
  booleanAttribute,
  ChangeDetectionStrategy,
  Component,
  computed,
  ElementRef,
  forwardRef,
  input,
  model,
  numberAttribute,
  output,
  signal,
  viewChild,
  ViewEncapsulation,
} from '@angular/core';
import { ControlValueAccessor, NG_VALUE_ACCESSOR } from '@angular/forms';

import { cn, type ClassValue } from '{{alias}}/utils';
import {
  INPUT_OTP_CHARS,
  INPUT_OTP_DIGITS,
  INPUT_OTP_DIGITS_AND_CHARS,
  type HbInputOtpPattern,
  type HbInputOtpSize,
  type HbInputOtpStatus,
} from './input-otp.variants';



let inputOtpUid = 0;
@Component({
  selector: 'hb-input-otp',
  template: `
    <ng-content />
    <input
      #native
      class="absolute inset-0 h-full w-full cursor-text bg-transparent text-transparent caret-transparent outline-none disabled:cursor-not-allowed [&::selection]:bg-transparent"
      autocomplete="one-time-code"
      [id]="hbInputId() || uid"
      [value]="hbValue()"
      [disabled]="isDisabled()"
      [readOnly]="hbReadonly()"
      [attr.maxlength]="hbMaxLength()"
      [attr.inputmode]="inputMode()"
      [attr.name]="hbName() || null"
      [attr.aria-invalid]="hbInvalid() || null"
      [attr.aria-label]="hbAriaLabel() || null"
      (input)="onInput($event)"
      (focus)="onFocus()"
      (blur)="onBlur()"
      (keyup)="syncCaret()"
      (pointerup)="syncCaret()"
      (select)="syncCaret()"
    />
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  encapsulation: ViewEncapsulation.None,
  providers: [
    { provide: NG_VALUE_ACCESSOR, useExisting: forwardRef(() => HbInputOtpComponent), multi: true },
  ],
  host: {
    '[class]': 'hostClasses()',
    '[attr.data-slot]': "'input-otp'",
    '[attr.data-disabled]': 'isDisabled() || null',
  },
  exportAs: 'hbInputOtp',
})
export class HbInputOtpComponent implements ControlValueAccessor {
  private readonly native = viewChild.required<ElementRef<HTMLInputElement>>('native');

  protected readonly uid = `hb-input-otp-${++inputOtpUid}`;

  readonly hbMaxLength = input(6, { transform: numberAttribute });
  readonly hbValue = model('');
  readonly hbPattern = input<HbInputOtpPattern>('digits');
  readonly hbSize = input<HbInputOtpSize>('md');
  readonly hbStatus = input<HbInputOtpStatus>('default');
  readonly hbDisabled = input(false, { transform: booleanAttribute });
  readonly hbReadonly = input(false, { transform: booleanAttribute });
  readonly hbInvalid = input(false, { transform: booleanAttribute });
  readonly hbRing = input(true, { transform: booleanAttribute });
  readonly hbAutoFocus = input(false, { transform: booleanAttribute });
  readonly hbName = input<string>('');
  readonly hbInputId = input<string>('');
  readonly hbAriaLabel = input<string>('');
  readonly class = input<ClassValue>('');

  readonly hbChange = output<string>();
  readonly hbComplete = output<string>();

  private readonly focused = signal(false);
  private readonly caretStart = signal(0);
  private readonly caretEnd = signal(0);
  private readonly cvaDisabled = signal(false);

  readonly size = this.hbSize;
  readonly ring = this.hbRing;
  readonly status = computed<HbInputOtpStatus>(() =>
    this.hbInvalid() ? 'error' : this.hbStatus(),
  );
  readonly isDisabled = computed(() => this.hbDisabled() || this.cvaDisabled());

  protected readonly inputMode = computed(() => (this.hbPattern() === 'digits' ? 'numeric' : 'text'));
  protected readonly hostClasses = computed(() =>
    cn(
      'relative inline-flex items-center gap-2',
      this.isDisabled() && 'cursor-not-allowed opacity-50',
      this.class(),
    ),
  );

  private readonly perChar = computed<RegExp>(() => {
    const p = this.hbPattern();
    if (p instanceof RegExp) return new RegExp(p.source, p.flags.replace('g', ''));
    if (p === 'chars') return INPUT_OTP_CHARS;
    if (p === 'alphanumeric') return INPUT_OTP_DIGITS_AND_CHARS;
    return INPUT_OTP_DIGITS;
  });

  constructor() {
    afterNextRender(() => {
      if (this.hbAutoFocus() && !this.isDisabled()) this.native().nativeElement.focus();
    });
  }

  charAt(index: number): string {
    return this.hbValue()[index] ?? '';
  }
  isActive(index: number): boolean {
    if (!this.focused()) return false;
    const start = this.caretStart();
    const end = this.caretEnd();
    if (start !== end) return index >= start && index < end;
    return index === this.activeIndex(start);
  }
  showCaret(index: number): boolean {
    if (!this.focused() || this.caretStart() !== this.caretEnd()) return false;
    return index === this.activeIndex(this.caretStart()) && !this.charAt(index);
  }
  private activeIndex(caret: number): number {
    const max = this.hbMaxLength();
    return caret >= max ? max - 1 : caret;
  }

  private sanitize(value: string): string {
    const rx = this.perChar();
    return Array.from(value)
      .filter((c) => rx.test(c))
      .join('')
      .slice(0, this.hbMaxLength());
  }

  protected onInput(event: Event): void {
    const el = event.target as HTMLInputElement;
    const next = this.sanitize(el.value);
    if (el.value !== next) el.value = next;
    el.setSelectionRange(next.length, next.length);
    this.caretStart.set(next.length);
    this.caretEnd.set(next.length);
    if (next !== this.hbValue()) {
      this.hbValue.set(next);
      this.onChange(next);
      this.hbChange.emit(next);
      if (next.length === this.hbMaxLength()) this.hbComplete.emit(next);
    }
  }
  protected onFocus(): void {
    this.focused.set(true);
    this.syncCaret();
  }
  protected onBlur(): void {
    this.focused.set(false);
    this.onTouched();
  }
  protected syncCaret(): void {
    const el = this.native().nativeElement;
    this.caretStart.set(el.selectionStart ?? 0);
    this.caretEnd.set(el.selectionEnd ?? 0);
  }

  focus(): void {
    this.native().nativeElement.focus();
  }

  protected onChange: (value: string) => void = () => {};
  protected onTouched: () => void = () => {};
  writeValue(value: string): void {
    this.hbValue.set(this.sanitize(value ?? ''));
  }
  registerOnChange(fn: (value: string) => void): void {
    this.onChange = fn;
  }
  registerOnTouched(fn: () => void): void {
    this.onTouched = fn;
  }
  setDisabledState(isDisabled: boolean): void {
    this.cvaDisabled.set(isDisabled);
  }
}

import { HbInputOtpGroupComponent } from './input-otp-group.component';
import { HbInputOtpSeparatorComponent } from './input-otp-separator.component';
import { HbInputOtpSlotComponent } from './input-otp-slot.component';
import { HbInputOtpComponent } from './input-otp.component';

export const HbInputOtpImports = [
  HbInputOtpComponent,
  HbInputOtpGroupComponent,
  HbInputOtpSlotComponent,
  HbInputOtpSeparatorComponent,
] as const;

import { cva, type VariantProps } from 'class-variance-authority';

import { cn } from '{{alias}}/utils';

export const INPUT_OTP_DIGITS = /[0-9]/;
export const INPUT_OTP_CHARS = /[a-zA-Z]/;
export const INPUT_OTP_DIGITS_AND_CHARS = /[a-zA-Z0-9]/;

export type HbInputOtpPatternPreset = 'digits' | 'chars' | 'alphanumeric';
export type HbInputOtpPattern = HbInputOtpPatternPreset | RegExp;

export const inputOtpSlotVariants = cva(
  cn(
    'pointer-events-none relative flex items-center justify-center border-y border-r border-input text-foreground shadow-xs transition-all outline-none',
    'first:rounded-l-md first:border-l last:rounded-r-md',
    'data-[active=true]:z-10 data-[active=true]:border-ring data-[active=true]:ring-[3px] data-[active=true]:ring-ring/50',
    'data-[disabled=true]:cursor-not-allowed data-[disabled=true]:opacity-50',
  ),
  {
    variants: {
      size: {
        xs: 'size-7 text-xs',
        sm: 'size-8 text-sm',
        md: 'size-9 text-sm',
        lg: 'size-10 text-base',
        xl: 'size-11 text-lg',
      },
      status: {
        default: '',
        success:
          'data-[active=true]:border-success data-[active=true]:ring-success/30',
        warning:
          'data-[active=true]:border-warning data-[active=true]:ring-warning/30',
        error:
          'border-destructive data-[active=true]:border-destructive data-[active=true]:ring-destructive/30',
      },
      ring: {
        true: '',
        false: 'data-[active=true]:ring-0',
      },
    },
    defaultVariants: { size: 'md', status: 'default', ring: true },
  },
);

export type HbInputOtpSize = NonNullable<VariantProps<typeof inputOtpSlotVariants>['size']>;
export type HbInputOtpStatus = NonNullable<VariantProps<typeof inputOtpSlotVariants>['status']>;

